   210→	ae.ResponseObject, err = encodeObject(obj, gv, s)
   211→	if err != nil {
   212→		klog.ErrorS(err, "Encoding failed of response object", "auditID", ae.AuditID, "obj", obj)
   213→	}
   214→}
